<template>
    <view class="contain">
        <u-navbar title="予約" :safeAreaInsetTop="true" bgColor="rgb(251,251,253)" :placeholder="true">
            <view class="u-nav-slot" slot="left">
                <image src="../../static/icons/tclose.png" style="width: 60upx;height: 60upx;" @click="toIndex"></image>
            </view>
            <view class="u-nav-slot" slot="right">
                <image src="../../static/icons/fillSetting.png" style="width: 60upx;height: 60upx;"
                    @click="showSetting"></image>
            </view>
        </u-navbar>
        <view class="top">
            <view class="topContent">
                <view class="content_item" @click="toNotice">
                    <view class="item_left">
                        予約通知
                    </view>
                    <view class="item_right bk" v-text="totalNum"></view>
                </view>
                <view class="content_item">
                    <view class="item_left">
                        今日の予約
                    </view>
                    <view class="item_right" v-text="todayNum"></view>
                </view>
            </view>
        </view>
        <view class="content">
            <view class="tabs">
                <view class="tab">
                    <view class="tab_item" @click="changeTab('day')" :class="status == 'day'? 'active' : '' ">
                        日
                    </view>
                    <view class="tab_item" @click="changeTab('week')" :class="status == 'week'? 'active' : '' ">
                        週
                    </view>
                </view>
            </view>
            <view class="askForName" v-if="status == 'week'">
                <view class="name_item" :class="current == 0? 'active' : ''" @click="changeName(0,0)">指名なし</view>
                <view class="name_item" :class="current == index + 1? 'active' : ''"
                    @click="changeName(item.id,index+1)" v-for="(item,index) in staff" v-text="item.name"></view>
            </view>
            <!-- 日历组件 -->
            <view class="calendar">
                <lxCalendar @change="change"></lxCalendar>
            </view>
            <!-- 日 -->
            <view v-if="status == 'day'">
                <progres :manager="managers" @addNew="addNewAppointment" :times="times"></progres>
            </view>
            <!-- 周 -->
            <view v-if="status == 'week'">
                <week :times="times" @addNew="addNewAppointment" :weekData="weekData"></week>
            </view>
            <!-- 设置 -->
            <setting v-if="setting" @close="closeSetting" @goDetail="checkDetail"></setting>
            <!-- 设置详情 -->
            <settingDetail v-if="showDetail" :info="info" @closeDetail="closeDetail"></settingDetail>
            <!-- 新增预约 -->
            <newAppoint @cancel="changeAdd" v-if="addNew"></newAppoint>
        </view>
    </view>
</template>

<script>
    import lxCalendar from "@/components/lx-calendar/lx-calendar.vue"
    import progres from "@/components/progress/progress.vue"
    import week from "@/components/week/week.vue"
    import setting from "@/components/appointment/add.vue"
    import settingDetail from "@/components/appointment/addDetail.vue"
    import newAppoint from "@/components/appointment/new.vue"
    import {
        getAppointmentList,
        getCalendar,
        getStaffList,
        getAppointNoticeList
    } from "@/api/index.js"
    export default {
        components: {
            lxCalendar,
            progres,
            week,
            setting,
            settingDetail,
            newAppoint
        },
        data() {
            return {
                status: "day",
                setting: false, //设置
                current: 0,
                staffId: 0,
                showDetail: false, // 设置详情
                addNew: false, // 新增预约
                info: {},
                times: [
                    {
                        time: "08:00"
                    },
                    {
                        time: "08:30"
                    },
                    {
                        time: "09:00"
                    },
                    {
                        time: "09:30"
                    },
                    {
                        time: "10:00"
                    },
                    {
                        time: "10:30"
                    },
                    {
                        time: "11:00"
                    },
                    {
                        time: "11:30"
                    },
                    {
                        time: "12:00"
                    },
                    {
                        time: "12:30"
                    },
                    {
                        time: "13:00"
                    },
                    {
                        time: "13:30"
                    },
                    {
                        time: "14:00"
                    },
                    {
                        time: "14:30"
                    },
                    {
                        time: "15:00"
                    },
                    {
                        time: "15:30"
                    },
                    {
                        time: "16:00"
                    },
                    {
                        time: "16:30"
                    },
                    {
                        time: "17:00"
                    },
                    {
                        time: "17:30"
                    },
                    {
                        time: "18:00"
                    },
                    {
                        time: "18:30"
                    },
                    {
                        time: "19:00"
                    },
                    {
                        time: "19:30"
                    },
                    {
                        time: "20:00"
                    },
                    {
                        time: "20:30"
                    },
                    {
                        time: "21:00"
                    },
                    {
                        time: "21:30"
                    },
                    {
                        time: "22:00"
                    },
                    {
                        time: "22:30"
                    },
                    {
                        time: "23:00"
                    },
                    {
                        time: "23:30"
                    },
                ],
                array: [],
                manager: [],
                managers: [],
                weekData: [],
                staff: [],
                selectDate: "",
                currentDate: "",
                totalNum: 0,
                todayNum: 0
            }
        },
        created() {
            let that = this
            that.getList(that.getToday())
            that.getStaffData()
            // that.getWeekDate()
        },
        onShow() {
            let that = this
            that.getLists()
        },
        methods: {
            // 切换日、周
            changeTab(e) {
                let that = this
                that.status = e
                if (e != "week") {
                    that.getList(that.getToday())
                } else {
                    that.selectDate = that.formatDate(that.getWeekDate(that.getToday()))
                    that.getWeekList(that.formatDate(that.getWeekDate(that.getToday())))
                }
            },
            getLists(){
                let that = this 
              getAppointNoticeList(1).then((res) => {
                  console.log('list',res)
                  if(res.code == 200){
                      that.totalNum = res.data.unread_count
                      that.todayNum = res.data.today_count
                  }
              })  
            },
            getStaffData() {
                let that = this
                let data = {}
                data.id = 0
                data.start_time = ""
                data.end_time = ""
                getStaffList(data).then((res) => {
                    if (res.code == 200) {
                        that.staff = res.data.admins
                    }
                })
            },
            // 获取本周日期
            getWeekDate(dms) {
                let that = this
                let today = new Date(dms);
                //构建当前日期,格式：2022-08-22 00:00:00
                let year = today.getFullYear(); //本年 
                let month = today.getMonth() + 1; //本月
                let day = today.getDate(); //本日
                let newDate = new Date(year + "-" + month + "-" + day + " 00:00:00"); //年月日拼接
                let nowTime = newDate.getTime(); //当前的时间戳
                let weekDay = newDate.getDay(); //当前星期 0.1.2.3.4.5.6 【0 = 周日】
                let oneDayTime = 24 * 60 * 60 * 1000; //一天的总ms
                let sundayTime = (7 - weekDay) * oneDayTime + nowTime; //本周日的时间戳
                let lastSundayTime = nowTime - (weekDay + 0) * oneDayTime; //上周日的时间戳
                return lastSundayTime
            },
            // 格式化日期
            formatDate(ms) {
                const date = new Date(ms)
                const Y = date.getFullYear()
                const M = date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1
                const D = date.getDate()
                return `${Y}-${M}-${D}`
            },
            // 切换日期
            change(e) {
                console.log("e",e)
                let that = this
                if (that.status == "week") {
                    that.getWeekList(that.formatDate(that.getWeekDate(e.fulldate + " 00:00:00")))
                    that.selectDate = that.formatDate(that.getWeekDate(e.fulldate + " 00:00:00"))
                } else {
                    that.getList(e.fulldate)
                }
            },
            toSet() {
                let that = this
                let array = that.manager
                that.managers = array
            },
            // 获取今日日期
            getToday() {
                let that = this
                let date = new Date()
                let year = date.getFullYear()
                let month = date.getMonth() + 1
                let day = date.getDate()
                month = (month > 9) ? month : ("0" + month);
                day = (day < 10) ? ("0" + day) : day;
                let today = year + "-" + month + "-" + day
                return today
            },
            // 颜色转换
            hexToRgba(hex) {
                if (!hex) hex = '#ededed';
                let rgb = 'rgb(' + parseInt('0x' + hex.slice(1, 3)) + ',' +
                    parseInt('0x' + hex.slice(3, 5)) + ',' +
                    parseInt('0x' + hex.slice(5, 7)) + ')'
                return rgb
            },
            getHour(s1, s2) {
                var reDate = /\d{4}-\d{1,2}-\d{1,2} /;
                s1 = new Date((reDate.test(s1) ? s1 : '2018-1-1 ' + s1).replace(/-/g, '/'));
                s2 = new Date((reDate.test(s2) ? s2 : '2018-1-1 ' + s2).replace(/-/g, '/'));
                var ms = s2.getTime() - s1.getTime();
                if (ms < 0) return 0;
                return Math.floor(ms / 1000 / 60 / 60); //小时
            },
            // 关闭新增预约
            changeAdd(e) {
                let that = this
                if (e == "close") {
                    that.addNew = false
                }

                if (e == "refresh") {
                    that.addNew = false
                    that.getList(that.getToday())
                    that.getWeekList(that.formatDate(that.getWeekDate(that.getToday())))
                }
            },
            // 获取每日预约列表
            getList(date) {
                let that = this
                let data = {}
                data.date = date
                data.id = 0
                data.type = "day"
                getAppointmentList(data).then((res) => {
                    if (res.code == 200) {
                        let tem = []
                        // that.totalNum = res.data.order_total
                        // that.todayNum = res.data.order_today
                        let timeArr = JSON.parse(JSON.stringify(that.times))
                        res.data.admins.forEach((val, index) => {
                            let obj = {}
                            obj.name = val.name
                            obj.times = that.times
                            obj.total = that.times.length
                            if (val.color) {
                                obj.color = that.hexToRgba(val.color)
                            } else {
                                obj.color = "rgb(23, 84, 145)"
                            }
                            obj.events = []
                            val.orders.forEach((value, idx) => {
                                let t = {}
                                t.start = value.start_time
                                t.end = value.end_time
                                t.duration = value.m / 60
                                t.name = value.name
                                t.event = value.cate_name
                                obj.events.push(t)
                            })
                            tem.push(obj)
                        })
                        that.manager = tem
                        that.toSet()
                    }
                })
            },
            // 获取每周预约列表
            getWeekList(date) {
                let that = this
                let data = {}
                data.date = date
                data.type = "week"
                data.id = that.staffId
                getAppointmentList(data).then((res) => {
                    if (res.code == 200) {
                        let array = res.data.data
                        array.forEach((val, index) => {
                            val.times = that.times
                        })
                        that.weekData = array
                    }
                })
            },
            // 切换员工
            changeName(e, index) {
                let that = this
                that.current = index
                that.staffId = e
                that.getWeekList(that.selectDate)
            },
            // 显示设置组件
            showSetting() {
                let that = this
                that.setting = true
            },
            // 关闭设置组件
            closeSetting() {
                this.setting = false
            },
            // 显示设置详情
            checkDetail(e) {
                if (e) {
                    this.setting = false
                    this.showDetail = true
                }
                this.info = e
            },
            // 关闭设置详情
            closeDetail(e) {
                this.showDetail = false
                this.setting = true
            },
            // 跳转消息通知
            toNotice() {
                uni.navigateTo({
                    url: "../appointment/notice/notice"
                })
            },
            // 返回首页
            toIndex() {
                uni.switchTab({
                    url: "../index/index"
                })
            },
            // 新增预约
            addNewAppointment(e) {
                this.addNew = true
            }
        }
    }
</script>

<style lang="scss">
